class SecureModelDownloader:
    def __init__(self, allowed_domains: list = None, max_file_size: int = 100 * 1024 * 1024):
        self.allowed_domains = allowed_domains or [
            "https://download.pytorch.org",
            "https://huggingface.co",
            "https://storage.googleapis.com"
        ]
        self.max_file_size = max_file_size
        self.session = requests.Session()
        
    def is_domain_allowed(self, url: str) -> bool:
        return any(domain in url for domain in self.allowed_domains)
    
    def validate_url(self, url: str) -> bool:
        if not url.startswith(('http://', 'https://')):
            return False
        return self.is_domain_allowed(url)
    
    def download_model(self, url: str, save_path: str = None) -> str:
        if not self.validate_url(url):
            raise ValueError(f"URL not allowed: {url}")
            
        response = self.session.get(url, stream=True)
        response.raise_for_status()
        
        if int(response.headers.get('content-length', 0)) > self.max_file_size:
            raise ValueError("File too large")
            
        if save_path is None:
            save_path = tempfile.mktemp(suffix='.pt')
            
        with open(save_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)
                    
        return save_path
    
    def verify_model_integrity(self, file_path: str, expected_hash: str = None) -> bool:
        if expected_hash is None:
            return True
            
        with open(file_path, 'rb') as f:
            file_hash = hashlib.sha256(f.read()).hexdigest()
            
        return file_hash == expected_hash

class SecureModelLoader:
    def __init__(self, model_dir: str = "models"):
        self.model_dir = Path(model_dir)
        self.model_dir.mkdir(exist_ok=True)
        
    def load_model_from_url(self, url: str, 
                          downloader: SecureModelDownloader,
                          expected_hash: str = None,
                          map_location: str = 'cpu') -> torch.nn.Module:
        
        # Download model
        temp_path = downloader.download_model(url)
        
        try:
            # Verify integrity
            if expected_hash and not downloader.verify_model_integrity(temp_path, expected_hash):
                raise ValueError("Model integrity check failed")
                
            # Load model securely
            model = torch.load(temp_path, map_location=map_location, weights_only=True)
            
            # Move to appropriate device
            if torch.cuda.is_available() and map_location != 'cpu':
                model = model.cuda()
                
            return model
            
        finally:
            # Clean up temporary file
            if os.path.exists(temp_path):
                os.remove(temp_path)

class SecureFineTuner:
    def __init__(self, model: torch.nn.Module, device: str = 'cpu'):
        self.model = model
        self.device = device
        self.model.to(device)
        
    def fine_tune(self, 
                 train_loader: torch.utils.data.DataLoader,
                 val_loader: torch.utils.data.DataLoader,
                 num_epochs: int = 5,
                 learning_rate: float = 1e-4,
                 save_path: str = None) -> Dict[str, Any]:
        
        # Set model to training mode
        self.model.train()
        
        # Setup optimizer
        optimizer = torch.optim.AdamW(self.model.parameters(), lr=learning_rate)
        criterion = torch.nn.CrossEntropyLoss()
        
        # Training loop
        train_losses = []
        val_accuracies = []
        
        for epoch in range(num_epochs):
            epoch_loss = 0.0
            self.model.train()
            
            for batch_idx, (data, target) in enumerate(train_loader):
                data, target = data.to(self.device), target.to(self.device)
                
                optimizer.zero_grad()
                output = self.model(data)
                loss = criterion(output, target)
                loss.backward()
                
                # Gradient clipping to prevent backdoors
                torch.nn.utils.clip_grad_norm_(self.model.parameters(), max_norm=1.0)
                
                optimizer.step()
                epoch_loss += loss.item()
                
            avg_loss = epoch_loss / len(train_loader)
            train_losses.append(avg_loss)
            
            # Validation
            val_acc = self._validate(val_loader)
            val_accuracies.append(val_acc)
            
        # Save model if path provided
        if save_path:
            torch.save(self.model.state_dict(), save_path)
            
        return {
            'train_losses': train_losses,
            'val_accuracies': val_accuracies,
            'final_accuracy': val_accuracies[-1] if val_accuracies else 0.0
        }
        
    def _validate(self, val_loader: torch.utils.data.DataLoader) -> float:
        self.model.eval()
        correct = 0
        total = 0
        
        with torch.no_grad():
            for data, target in val_loader:
                data, target = data.to(self.device), target.to(self.device)
                outputs = self.model(data)
                _, predicted = torch.max(outputs.data, 1)
                total += target.size(0)
                correct += (predicted == target).sum().item()
                
        return correct / total

